import{_ as e,o as l,c as i,a2 as t}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"图表交易","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/desktop-tools/chart-trading.md","filePath":"zh-CN/stock-trading/desktop-tools/chart-trading.md"}'),r={name:"stock-trading/desktop-tools/chart-trading.md"};function o(h,a,d,n,s,c){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="图表交易" tabindex="-1">图表交易 <a class="header-anchor" href="#图表交易" aria-label="Permalink to &quot;图表交易&quot;">​</a></h1><p>在 K 线图上进行快捷下单、改单、止盈止损及一键平仓的功能说明。</p><h2 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h2><p>图表交易是桌面端特色功能，支持在 K 线图上同时看盘、分析和下单，无需切换界面即可完成交易操作。</p><h2 id="_5-大特色" tabindex="-1">5 大特色 <a class="header-anchor" href="#_5-大特色" aria-label="Permalink to &quot;5 大特色&quot;">​</a></h2><ol><li>图表快捷下单：直接在图表上点击下单，操作高效</li><li>拖动改单：拖动委托线即可修改挂单价格</li><li>止盈止损：下单时可同步设置止盈止损价位</li><li>可视化持仓：持仓成本线直观显示在图表上</li><li>一键平仓：快速平掉当前持仓</li></ol><h2 id="开启入口" tabindex="-1">开启入口 <a class="header-anchor" href="#开启入口" aria-label="Permalink to &quot;开启入口&quot;">​</a></h2><ul><li>入口一：日内交易面板内开启图表交易模式</li><li>入口二：组件工具箱 &gt; 交易 &gt; 图表交易</li></ul><p>首次使用需验证交易密码。</p><h2 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h2><h3 id="设置交易数量" tabindex="-1">设置交易数量 <a class="header-anchor" href="#设置交易数量" aria-label="Permalink to &quot;设置交易数量&quot;">​</a></h3><p>支持按比例设置下单数量：</p><ul><li>1/4 仓、1/3 仓、1/2 仓、全仓</li></ul><h3 id="头部快捷交易" tabindex="-1">头部快捷交易 <a class="header-anchor" href="#头部快捷交易" aria-label="Permalink to &quot;头部快捷交易&quot;">​</a></h3><p>在图表顶部可快速按以下价格下单：</p><ul><li>市价单</li><li>买一价</li><li>卖一价</li></ul><h3 id="k-线下单-限价单" tabindex="-1">K 线下单（限价单） <a class="header-anchor" href="#k-线下单-限价单" aria-label="Permalink to &quot;K 线下单（限价单）&quot;">​</a></h3><p>在 K 线图任意价格位置点击，即可按该价格提交限价单。</p><h3 id="改单" tabindex="-1">改单 <a class="header-anchor" href="#改单" aria-label="Permalink to &quot;改单&quot;">​</a></h3><p>支持 3 种改单方式：</p><ol><li>拖动委托线：直接拖动图表上的挂单线到目标价格</li><li>详情页改单：点击委托线进入订单详情后修改</li><li>订单列表改单：在订单列表组件中选中订单后改单</li></ol><h3 id="撤单" tabindex="-1">撤单 <a class="header-anchor" href="#撤单" aria-label="Permalink to &quot;撤单&quot;">​</a></h3><ul><li>单笔撤单：点击委托线上的 X 按钮</li><li>批量撤单：在订单列表中多选后批量撤销</li></ul><h3 id="持仓信息" tabindex="-1">持仓信息 <a class="header-anchor" href="#持仓信息" aria-label="Permalink to &quot;持仓信息&quot;">​</a></h3><p>图表上显示持仓成本线及持仓数量，方便实时掌握盈亏情况。</p><h3 id="快速平仓" tabindex="-1">快速平仓 <a class="header-anchor" href="#快速平仓" aria-label="Permalink to &quot;快速平仓&quot;">​</a></h3><p>在持仓信息区域点击平仓按钮，一键平掉全部或部分持仓。</p><h2 id="附加单设置" tabindex="-1">附加单设置 <a class="header-anchor" href="#附加单设置" aria-label="Permalink to &quot;附加单设置&quot;">​</a></h2><p>附加单是指在主委托单成交后自动触发的止盈/止损单。支持 3 种价格设置方式：</p><h3 id="_1-价格-直接指定" tabindex="-1">1. 价格（直接指定） <a class="header-anchor" href="#_1-价格-直接指定" aria-label="Permalink to &quot;1. 价格（直接指定）&quot;">​</a></h3><p>直接填写止盈或止损的目标价格。</p><p>示例：主单买入价 100 元，止损设置为 95 元，则当价格跌至 95 元时触发止损单。</p><h3 id="_2-价差-相对委托价" tabindex="-1">2. 价差（相对委托价） <a class="header-anchor" href="#_2-价差-相对委托价" aria-label="Permalink to &quot;2. 价差（相对委托价）&quot;">​</a></h3><p>以委托价为基准，设置一个固定的价格差值。</p><p>示例：委托价 100 元，止损价差设为 -5 元，则止损触发价 = 100 - 5 = 95 元。</p><h3 id="_3-档位-最小变动单位-×-档数" tabindex="-1">3. 档位（最小变动单位 × 档数） <a class="header-anchor" href="#_3-档位-最小变动单位-×-档数" aria-label="Permalink to &quot;3. 档位（最小变动单位 × 档数）&quot;">​</a></h3><p>以最小价格变动单位（tick）为基础，设置档数倍数。</p><p>示例：最小变动单位为 0.01 元，止损设为 -500 档，则止损触发价 = 委托价 - 0.01 × 500 = 委托价 - 5 元。</p><h2 id="图表模式与盘外交易限制" tabindex="-1">图表模式与盘外交易限制 <a class="header-anchor" href="#图表模式与盘外交易限制" aria-label="Permalink to &quot;图表模式与盘外交易限制&quot;">​</a></h2><ul><li>TradingView 模式图表不显示附加单委托线，建议切换为经典模式使用</li><li>美股不支持夜盘期间使用图表交易下单</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/desktop-tools">桌面端工具</a></li><li><a href="/wiki/stock-trading">股票交易</a></li></ul>',42)])])}const b=e(r,[["render",o]]);export{p as __pageData,b as default};
